import { scaleBand } from 'd3-scale';
import { type ReactNode } from 'react';

import { useGridPlotSize } from '../../core/components/chart-grid/hooks/useGridPlotSize.js';
import {
  CATEGORICAL_BARS_INNER_PADDING,
  CATEGORICAL_BARS_OUTER_PADDING,
} from '../../core/constants.js';
import { CategoricalBarChartScalesContext } from '../contexts/CategoricalBarChartScalesContext.js';
import { useCategoricalBarChartBaseConfig } from '../hooks/useCategoricalBarChartBaseConfig.js';
import { useCategoricalBarChartValueAxisConfig } from '../hooks/useCategoricalBarChartValueAxisConfig.js';
import { useCategoricalBarFilteredData } from '../hooks/useCategoricalBarFilteredData.js';
import { getCategoricalValueScale } from '../utils/get-value-scale.js';
import { isVertical } from '../utils/layout.js';

export const CategoricalBarScalesProvider = ({
  children,
}: {
  children: ReactNode;
}) => {
  const { filteredCategories, unit, filteredDimensions, minMaxPerUnit } =
    useCategoricalBarFilteredData();
  const { min, max, scale } = useCategoricalBarChartValueAxisConfig();
  const { layout } = useCategoricalBarChartBaseConfig();
  const isHorizontal = !isVertical(layout);

  const { width, height } = useGridPlotSize();

  const categoryScale = scaleBand()
    .domain(filteredCategories.map(({ id }) => id))
    .range(isHorizontal ? [0, height] : [0, width])
    .paddingInner(CATEGORICAL_BARS_INNER_PADDING)
    .paddingOuter(CATEGORICAL_BARS_OUTER_PADDING);

  const dimensionScale = scaleBand()
    .domain(filteredDimensions)
    .range([0, categoryScale.bandwidth()])
    .paddingInner(CATEGORICAL_BARS_INNER_PADDING);

  const size = isHorizontal ? width : height;

  const domainMinMax = minMaxPerUnit.get(unit) ?? { min: 0, max: 0 };

  const valueScale = getCategoricalValueScale(
    domainMinMax,
    size,
    isHorizontal,
    scale,
    { min, max },
  );

  return (
    <CategoricalBarChartScalesContext.Provider
      value={{ categoryScale, valueScale, dimensionScale }}
    >
      {children}
    </CategoricalBarChartScalesContext.Provider>
  );
};
